from assay_engine.methodology.fence import Measurement, Interpretation, _contains_interpretation
from assay_engine._frozen import freeze

class DuckMap:
    def __init__(self, d):
        self._d = dict(d)
    def items(self):
        return self._d.items()
    def keys(self):
        return self._d.keys()
    def __getitem__(self, k):
        return self._d[k]
    def __iter__(self):
        return iter(self._d)

interp = Interpretation(value=1, basis=("p:h",), rationale="r", judged_by="op")
dm = DuckMap({'k': interp})

# Is DuckMap hashable? (default object hash = identity)
print("hash(dm):", hash(dm))

m = Measurement(value=dm, produced_by="p", inputs_hash="h")
# BEFORE mutation: is the Interpretation actually retrievable inside the Measurement?
print("m.value['k'] is interp:", m.value['k'] is interp)
print("type of m.value['k']:", type(m.value['k']).__name__)

# Confirm the frozen Measurement is hashable (so it passes downstream)
print("hash(m):", hash(m))

# Confirm immutability is broken: mutate after freeze
m.value._d['new'] = 'sneaky'
print("m.value has new key:", 'new' in m.value._d)
EOF
